  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Lab 4: Nanoservices (Kubernetes)</title>
  <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" rel="stylesheet" />
  <script defer src="https://cdn.jsdelivr.net/npm/alpinejs@3.x.x/dist/cdn.min.js"></script>
</head>
<body class="bg-light">
  <div class="container py-5" x-data="app()" x-init="init()">
    <h1 class="mb-3">Lab 4: Nanoservices (Kubernetes)</h1>
    <div class="card mb-4">
      <div class="card-body">
        <div class="d-flex justify-content-between align-items-start">
          <div>
            <h5 class="card-title mb-1">Architecture</h5>
            <div class="small text-muted">What this UI is talking to right now</div>
            <div class="mt-2">
              <span class="badge text-bg-secondary" x-text="archLabel || 'unknown'"></span>
            </div>
          </div>
          <div class="text-end">
            <h5 class="card-title mb-1">Last request</h5>
            <div class="small text-muted" x-text="lastReq.label || '—'"></div>
            <div class="fw-semibold" x-text="lastReq.ms != null ? `${lastReq.ms.toFixed(1)} ms` : '—'"></div>
          </div>
        </div>
        <hr />
        <div class="d-flex flex-wrap gap-2">
          <button class="btn btn-primary" @click="ping()">Ping</button>
          <button class="btn btn-outline-primary" @click="checkout(1, 100)">Checkout sku=1 subtotal=100</button>
          <button class="btn btn-outline-primary" @click="checkout(3, 100)">Checkout sku=3 subtotal=100 (out of stock)</button>
          <button class="btn btn-outline-secondary" @click="clearTimings()">Clear</button>
        </div>
        <div class="table-responsive mt-3">
          <table class="table table-sm mb-0">
            <thead>
              <tr><th>Method</th><th>Path</th><th>Status</th><th class="text-end">Time (ms)</th></tr>
            </thead>
            <tbody>
              <template x-for="r in timings" :key="r.id">
                <tr>
                  <td x-text="r.method"></td>
                  <td x-text="r.path"></td>
                  <td><span :class="r.ok ? 'badge text-bg-success' : 'badge text-bg-danger'" x-text="r.status"></span></td>
                  <td class="text-end" x-text="r.ms.toFixed(1)"></td>
                </tr>
              </template>
            </tbody>
          </table>
        </div>
      </div>
    </div>
    <div class="alert alert-info" x-show="result" x-text="result"></div>
  </div>
  <script>
    function app() {
      return {
        archLabel: "", timings: [], lastReq: {}, result: "",
        clearTimings() { this.timings = []; this.lastReq = {}; this.result = ""; },
        record(method, path, res, ms, ok) {
          const id = `${Date.now()}-${Math.random().toString(16).slice(2)}`;
          const entry = { id, method, path, ok, status: res ? res.status : "ERR", ms };
          this.lastReq = { label: `${method} ${path}`, ms };
          this.timings.unshift(entry);
          this.timings = this.timings.slice(0, 10);
        },
        async timedJson(method, path, options = {}) {
          const start = performance.now(); let res = null;
          try {
            res = await fetch(path, { method, ...options });
            const data = await res.json().catch(() => ({}));
            const ms = performance.now() - start;
            this.record(method, path, res, ms, res.ok);
            if (!res.ok) throw new Error(data.error || `HTTP ${res.status}`);
            return data;
          } catch (err) {
            const ms = performance.now() - start;
            this.record(method, path, res, ms, false);
            throw err;
          }
        },
        async init() {
          try {
            const info = await this.timedJson("GET", "/api/arch");
            this.archLabel = info.arch || "unknown";
          } catch (e) { this.archLabel = "unknown"; }
        },
        async ping() { await this.timedJson("GET", "/api/ping"); this.result = "Ping ok"; },
        async checkout(sku, subtotal) {
          try {
            const data = await this.timedJson("POST", "/api/checkout", {
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ sku, subtotal }),
            });
            this.result = JSON.stringify(data);
          } catch (e) { this.result = e.message; }
        },
      };
    }
  </script>
</body>
</html>

